using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define CACHE_LINE 512

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t {
  Points *points;
  long kmin;
  long kmax;
  long *kfinal;
  int pid;
  pthread_barrier_t *barrier;
};

class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) : n(n_) {}
  size_t read(float *dest, int dim, int num) override {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() override { return 0; }
  int feof() override { return n <= 0; }
  ~SimStream() override {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) override {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() override { return std::ferror(fp); }
  int feof() override { return std::feof(fp); }
  ~FileStream() override {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
static inline void tvsub(struct timeval *a, struct timeval *b, struct timeval *res) {
  res->tv_sec = a->tv_sec - b->tv_sec;
  res->tv_usec = a->tv_usec - b->tv_usec;
  if (res->tv_usec < 0) {
    res->tv_sec--;
    res->tv_usec += 1000000;
  }
}
#endif

static char *switch_membership;
static bool *is_center;
static int *center_table;
static int nproc;

static double serial;
static double cpu_gpu_memcpy;
static double memcpy_back;
static double gpu_malloc;
static double kernel;
static double gpu_free;
static int cnt_speedy;

int platform_id = 0;
int device_id = 0;

void _clCmdParams(int argc, char *argv[]) {
